#include <stdio.h>
#include <math.h>

int main(void) {
    double x1, y1, x2, y2, x3, y3;
    if (scanf("%lf %lf %lf %lf %lf %lf", &x1, &y1, &x2, &y2, &x3, &y3) != 6) return 0;
    double cross = x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2);
    if (fabs(cross) < 1e-9) printf("collinear\n");
    else printf("not collinear\n");
    return 0;
}
